import React, { useState, useEffect } from "react";
import api from "../api/api";
import { FaBox, FaFolderOpen, FaFileInvoiceDollar, FaMoneyBillWave, FaPlus, FaClipboardList, FaSun, FaMoon } from "react-icons/fa";
export default function Dashboard() {
// 🌙 ESTADO DEL MODO OSCURO
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem("tema") === "dark";
  });

  // 🔄 EFECTO PARA CAMBIAR EL TEMA DE BOOTSTRAP
  useEffect(() => {
    if (darkMode) {
      document.documentElement.setAttribute("data-bs-theme", "dark");
      localStorage.setItem("tema", "dark");
    } else {
      document.documentElement.setAttribute("data-bs-theme", "light");
      localStorage.setItem("tema", "light");
    }
  }, [darkMode]);

  const [resumen, setResumen] = useState({
    totalProductos: 0,
    totalCategorias: 0,
    facturasHoy: 0,
    ventasHoy: 0
  });

  const [cargando, setCargando] = useState(true);
  const nombreUsuario = localStorage.getItem("nombre") || "Administrador";

  useEffect(() => {
    obtenerEstadisticas();
  }, []);

  const obtenerEstadisticas = async () => {
    try {
      setCargando(true);
      // ✅ 1. Traemos Productos, Categorías y TODAS las Ventas
      const [resProd, resCat, resVentas] = await Promise.all([
        api.get("/productos"),
        api.get("/categorias"),
        api.get("/ventas")
      ]);
      
      // ✅ 2. Filtramos solo las ventas que coincidan con la fecha de HOY
      const fechaHoy = new Date().toLocaleDateString();
      const ventasDeHoy = (resVentas.data || []).filter((v) => {
        return new Date(v.createdAt).toLocaleDateString() === fechaHoy;
      });

      // ✅ 3. Sumamos el total de dinero generado hoy
      const dineroHoy = ventasDeHoy.reduce((suma, venta) => suma + (Number(venta.total) || 0), 0);

      // ✅ 4. Actualizamos el estado de forma segura
      setResumen({
        totalProductos: resProd.data?.length || 0,
        totalCategorias: resCat.data?.length || 0,
        facturasHoy: ventasDeHoy.length,
        ventasHoy: dineroHoy 
      });

    } catch (error) {
      console.error("❌ Error al cargar estadísticas:", error);
    } finally {
      setCargando(false);
    }
  };

  if (cargando) {
    return (
      <div className="container-fluid min-vh-100 d-flex flex-column align-items-center justify-content-center bg-light">
        <div className="spinner-border text-primary" style={{ width: '3rem', height: '3rem' }}></div>
        <p className="mt-3 fw-bold text-secondary">Cargando tu panel de control...</p>
      </div>
    );
  }

  return (
    <div className="container-fluid p-4 bg-light min-vh-100">
      <div className="mb-4">
        <h2 className="fw-bold text-dark">Panel de Control</h2>
        <p className="text-muted fs-5">¡Hola de nuevo, <span className="fw-bold text-primary">{nombreUsuario}</span>! Este es el resumen de tu negocio hoy.</p>
      </div>

      {/* 📊 TARJETAS DE MÉTRICAS */}
      <div className="row g-4">
        
        {/* Productos */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3 h-100 bg-white" style={{ borderLeft: "5px solid #0d6efd", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-primary bg-opacity-10 p-3 rounded-circle me-3 text-primary fs-4">
                <FaBox />
              </div>
              <div>
                <h6 className="text-muted mb-1 small text-uppercase fw-bold">Productos</h6>
                <h3 className="fw-bold mb-0 text-dark">{resumen.totalProductos}</h3>
              </div>
            </div>
          </div>
        </div>

        {/* Categorías */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3 h-100 bg-white" style={{ borderLeft: "5px solid #198754", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-success bg-opacity-10 p-3 rounded-circle me-3 text-success fs-4">
                <FaFolderOpen />
              </div>
              <div>
                <h6 className="text-muted mb-1 small text-uppercase fw-bold">Categorías</h6>
                <h3 className="fw-bold mb-0 text-dark">{resumen.totalCategorias}</h3>
              </div>
            </div>
          </div>
        </div>

        {/* Facturas Hoy (Nuevo para rellenar el espacio) */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3 h-100 bg-white" style={{ borderLeft: "5px solid #ffc107", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-warning bg-opacity-10 p-3 rounded-circle me-3 text-warning fs-4">
                <FaFileInvoiceDollar />
              </div>
              <div>
                <h6 className="text-muted mb-1 small text-uppercase fw-bold">Facturas Hoy</h6>
                <h3 className="fw-bold mb-0 text-dark">{resumen.facturasHoy}</h3>
              </div>
            </div>
          </div>
        </div>

        {/* Ingresos Hoy */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3 h-100 bg-white" style={{ borderLeft: "5px solid #dc3545", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-danger bg-opacity-10 p-3 rounded-circle me-3 text-danger fs-4">
                <FaMoneyBillWave />
              </div>
              <div>
                <h6 className="text-muted mb-1 small text-uppercase fw-bold">Ingresos Hoy</h6>
                <h3 className="fw-bold mb-0 text-dark">${resumen.ventasHoy.toFixed(2)}</h3>
              </div>
            </div>
          </div>
        </div>

      </div>

      {/* ⚡ ACCIONES RÁPIDAS */}
      <div className="row mt-5">
        <div className="col-md-12">
          <div className="card border-0 shadow-sm p-4 bg-white" style={{ borderRadius: "15px" }}>
            <h5 className="fw-bold mb-4 text-dark">⚡ Acciones Rápidas</h5>
            <div className="d-flex flex-wrap gap-3">
              <button 
                className="btn btn-primary px-4 py-2 shadow-sm fw-bold d-flex align-items-center rounded-pill" 
                onClick={() => window.location.href='/ventas'}
              >
                <FaPlus className="me-2" /> Nueva Venta
              </button>
              <button 
                className="btn btn-outline-secondary px-4 py-2 fw-bold d-flex align-items-center rounded-pill" 
                onClick={() => window.location.href='/productos'}
              >
                <FaClipboardList className="me-2" /> Gestionar Inventario
              </button>
            </div>
          </div>
        </div>
      </div>

    </div>
  );
}
